import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import axios from 'axios';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    
    // Check for Admin Hardcoded Login
    if (email === 'admin@university.com' && password === 'admin123') {
      localStorage.setItem('user', JSON.stringify({ full_name: 'Admin', email: email, role: 'admin' }));
      navigate('/add-event');
      return;
    }

    try {
      const response = await axios.post('http://localhost:5000/api/users/login', { email, password });
      if (response.data) {
        // Save user data (including profile pic) to localStorage
        localStorage.setItem('user', JSON.stringify(response.data.user));
        navigate('/'); // Redirect to Home
      }
    } catch (error) {
      alert(error.response?.data?.message || "Login failed");
    }
  };

  return (
    <div className="bg-[#f6f7f8] min-h-screen flex flex-col justify-center items-center">
      <div className="w-full max-w-md bg-white p-10 rounded-2xl shadow-2xl border border-slate-200">
        <h1 className="text-2xl font-black text-center mb-8">Login to UniEvents</h1>
        <form className="space-y-5" onSubmit={handleLogin}>
          <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full p-3.5 bg-[#f0f4f8] rounded-xl outline-none" placeholder="Email Address" required />
          <div className="relative">
            <input type={showPassword ? "text" : "password"} value={password} onChange={(e) => setPassword(e.target.value)} className="w-full p-3.5 bg-[#f0f4f8] rounded-xl outline-none" placeholder="Password" required />
            <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400">
               <span className="material-symbols-outlined">{showPassword ? "visibility_off" : "visibility"}</span>
            </button>
          </div>
          <button className="w-full bg-[#137fec] text-white font-bold py-4 rounded-xl shadow-lg" type="submit">Sign In</button>
        </form>
      </div>
    </div>
  );
};

export default Login;
